sql:
SELECT authors.author_name, policies.title, policies.date
FROM authors 
JOIN policies ON authors.author_id = policies.author_id;

SELECT author_id, author_name
FROM authors
ORDER BY author_name ASC;

SELECT policies.title, stakeholder_groups.group_name
FROM policies
INNER JOIN stakeholder_groups ON policies.stakeholder_group_id = stakeholder_groups.stakeholder_group_id;

SELECT stakeholder_name 
FROM stakeholders 
WHERE stakeholder_id NOT IN (
    SELECT DISTINCT stakeholder_id 
    FROM policy_stakeholders
);

external_knowledge:
- 'influencers' refers to the authors of the policies;
- 'groups they represent' refers to the stakeholder groups;
- 'policies they've authored' refers to the titles of the policies associated with the authors;
- 'the most accessed by the community' means the policies with the highest number of access events.

sql:
SELECT stakeholder_id, stakeholder_name
FROM stakeholders
WHERE position = 'CHCO';

SELECT policies.title AS 'Policy Title', authors.author_name AS 'Author Name'
FROM policies
LEFT JOIN authors ON policies.author_id = authors.author_id;

SELECT title
FROM policies
WHERE policy_id = 1 AND author_id = 1;

SELECT DISTINCT a.agency_name
FROM agencies a
INNER JOIN stakeholder_groups sg ON a.stakeholder_group_id = sg.stakeholder_group_id;
